package hyperliquid

import (
	"bytes"
	"crypto/ecdsa"
	"encoding/hex"
	"encoding/json"
	"math/big"
	"os"
	"strings"
	"testing"

	"github.com/ethereum/go-ethereum/crypto"
	"github.com/ethereum/go-ethereum/signer/core/apitypes"
	"github.com/stretchr/testify/require"
	"github.com/vmihailenco/msgpack/v5"
)

// Fixture-based signing tests that lock our pure-Go signing implementation
// to the official Hyperliquid Python SDK output. Fixtures live in
// testfixtures/signing_fixtures.json and are regenerated by
// testfixtures/gen_signing_fixtures.py.

type fxSig struct {
	R string `json:"r"`
	S string `json:"s"`
	V int    `json:"v"`
}

type fxExpectedL1 struct {
	MsgpackHex    string `json:"msgpack_hex"`
	ActionHashHex string `json:"action_hash_hex"`
	Signature     fxSig  `json:"signature"`
}

type fxExpectedUser struct {
	PrimaryType  string              `json:"primary_type"`
	PayloadTypes []map[string]string `json:"payload_types"`
	FinalAction  map[string]any      `json:"final_action"`
	Signature    fxSig               `json:"signature"`
}

type fxL1 struct {
	Inputs struct {
		Vault        any    `json:"vault"`
		Nonce        int64  `json:"nonce"`
		ExpiresAfter *int64 `json:"expires_after"`
		IsMainnet    bool   `json:"is_mainnet"`
	} `json:"inputs"`
	Expected fxExpectedL1 `json:"expected"`
}

type fxUser struct {
	Inputs struct {
		Action    map[string]any `json:"action"`
		IsMainnet bool           `json:"is_mainnet"`
	} `json:"inputs"`
	Expected fxExpectedUser `json:"expected"`
}

type fxFile struct {
	TestPrivateKey    string            `json:"test_private_key"`
	L1Actions         map[string]fxL1   `json:"l1_actions"`
	UserSignedActions map[string]fxUser `json:"user_signed_actions"`
}

func loadFixtures(t *testing.T) *fxFile {
	t.Helper()
	raw, err := os.ReadFile("testfixtures/signing_fixtures.json")
	require.NoError(t, err)
	var f fxFile
	require.NoError(t, json.Unmarshal(raw, &f))
	return &f
}

// loadPK extracts the test ECDSA private key from fixtures.
func loadPK(t *testing.T, f *fxFile) *ecdsa.PrivateKey {
	t.Helper()
	pkHex := strings.TrimPrefix(f.TestPrivateKey, "0x")
	pkBytes, err := hex.DecodeString(pkHex)
	require.NoError(t, err)
	pk, err := crypto.ToECDSA(pkBytes)
	require.NoError(t, err)
	return pk
}

// hexToBig parses a hex string (possibly with stripped leading zeros) to big.Int.
func hexToBig(s string) *big.Int {
	s = strings.TrimPrefix(s, "0x")
	if s == "" {
		return new(big.Int)
	}
	if len(s)%2 == 1 {
		s = "0" + s
	}
	b, ok := new(big.Int).SetString(s, 16)
	if !ok {
		return nil
	}
	return b
}

func assertSig(t *testing.T, got SignatureResult, want fxSig, label string) {
	t.Helper()
	if hexToBig(got.R).Cmp(hexToBig(want.R)) != 0 {
		t.Errorf("%s: R mismatch\n  got:  %s\n  want: %s", label, got.R, want.R)
	}
	if hexToBig(got.S).Cmp(hexToBig(want.S)) != 0 {
		t.Errorf("%s: S mismatch\n  got:  %s\n  want: %s", label, got.S, want.S)
	}
	if got.V != want.V {
		t.Errorf("%s: V mismatch: got %d want %d", label, got.V, want.V)
	}
}

// l1Cases defines the production-shape Go action structs that should encode to
// each fixture's expected msgpack bytes. Keeping this in code (not JSON) keeps
// the test legible and uses the actual Go types we ship.
func l1Cases() map[string]any {
	builder := &BuilderInfo{
		Builder: "0x1234567890abcdef1234567890abcdef12345678",
		Fee:     50,
	}
	orderWires := []OrderWire{{
		Asset:      0,
		IsBuy:      true,
		LimitPx:    "100.0",
		Size:       "1.0",
		ReduceOnly: false,
		OrderType:  OrderTypeWire{Limit: &LimitOrderTypeWire{Tif: "Gtc"}},
	}}
	return map[string]any{
		"plain_order_testnet": OrderAction{
			Type: "order", Orders: orderWires, Grouping: "na",
		},
		"builder_fee_order_testnet": OrderAction{
			Type: "order", Orders: orderWires, Grouping: "na", Builder: builder,
		},
		"builder_fee_order_mainnet": OrderAction{
			Type: "order", Orders: orderWires, Grouping: "na", Builder: builder,
		},
		"builder_fee_order_with_vault": OrderAction{
			Type: "order", Orders: orderWires, Grouping: "na", Builder: builder,
		},
		"update_leverage": UpdateLeverageAction{
			Type: "updateLeverage", Asset: 0, IsCross: true, Leverage: 10,
		},
		"update_isolated_margin": UpdateIsolatedMarginAction{
			Type: "updateIsolatedMargin", Asset: 0, IsBuy: true, Ntli: int64(1000000),
		},
	}
}

// encodeAction mirrors the encoding used inside actionHash, so the test can
// isolate msgpack-byte correctness from the hashing pipeline.
func encodeAction(action any) ([]byte, error) {
	var buf bytes.Buffer
	enc := msgpack.NewEncoder(&buf)
	enc.UseCompactInts(true)
	if err := enc.Encode(action); err != nil {
		return nil, err
	}
	return convertStr16ToStr8(buf.Bytes()), nil
}

func TestFixtures_L1_MsgpackBytes(t *testing.T) {
	f := loadFixtures(t)
	cases := l1Cases()
	for name, fx := range f.L1Actions {
		name, fx := name, fx
		action, ok := cases[name]
		if !ok {
			t.Logf("skip %s: no typed Go case", name)
			continue
		}
		t.Run(name, func(t *testing.T) {
			got, err := encodeAction(action)
			require.NoError(t, err)
			gotHex := hex.EncodeToString(got)
			if gotHex != fx.Expected.MsgpackHex {
				t.Errorf("msgpack mismatch\n  got:  %s\n  want: %s", gotHex, fx.Expected.MsgpackHex)
			}
		})
	}
}

func TestFixtures_L1_ActionHashAndSignature(t *testing.T) {
	f := loadFixtures(t)
	pk := loadPK(t, f)
	cases := l1Cases()
	for name, fx := range f.L1Actions {
		name, fx := name, fx
		action, ok := cases[name]
		if !ok {
			t.Logf("skip %s: no typed Go case", name)
			continue
		}
		t.Run(name, func(t *testing.T) {
			vault := ""
			if v, ok := fx.Inputs.Vault.(string); ok {
				vault = v
			}

			h := actionHash(action, vault, fx.Inputs.Nonce, fx.Inputs.ExpiresAfter)
			gotHash := hex.EncodeToString(h)
			if gotHash != fx.Expected.ActionHashHex {
				t.Errorf("action_hash mismatch\n  got:  %s\n  want: %s",
					gotHash, fx.Expected.ActionHashHex)
			}

			sig, err := SignL1Action(pk, action, vault,
				fx.Inputs.Nonce, fx.Inputs.ExpiresAfter, fx.Inputs.IsMainnet)
			require.NoError(t, err)
			assertSig(t, sig, fx.Expected.Signature, name)
		})
	}
}

func TestFixtures_UserSignedActions(t *testing.T) {
	f := loadFixtures(t)
	pk := loadPK(t, f)

	for name, fx := range f.UserSignedActions {
		name, fx := name, fx
		t.Run(name, func(t *testing.T) {
			payloadTypes := buildPayloadTypes(fx.Expected.PayloadTypes)
			action := cloneAction(fx.Inputs.Action)

			sig, err := SignUserSignedAction(pk, action, payloadTypes,
				fx.Expected.PrimaryType, fx.Inputs.IsMainnet)
			require.NoError(t, err)
			assertSig(t, sig, fx.Expected.Signature, name)
		})
	}
}

func buildPayloadTypes(in []map[string]string) []apitypes.Type {
	out := make([]apitypes.Type, len(in))
	for i, t := range in {
		out[i] = apitypes.Type{Name: t["name"], Type: t["type"]}
	}
	return out
}

func cloneAction(in map[string]any) map[string]any {
	out := make(map[string]any, len(in))
	for k, v := range in {
		out[k] = v
	}
	return out
}
